using System;
using System.Threading.Tasks;
using Microsoft.EntityFrameworkCore;

public class EventBookingSystemContext : DbContext
{
    // Assumes that the Events table is already defined with properties like Id, Name, SeatsAvailable etc., 
    public DbSet<Event> Events { get; set; }
    
    protected override void OnConfiguring(DbContextOptionsBuilder optionsBuilder)
        => optionsBuilder.UseSqlServer(@"Data Source=MyDatabase.db");
}

public class Event
{
    public int Id { get; set; }
    public string Name { get; set; }
    public int SeatsAvailable { get; set; }
    
    // Add other properties as required by your application
}

public class BookingService
{
    private readonly EventBookingSystemContext _context;

    public BookingService(EventBookingSystemContext context)
    {
        _context = context;
    }

    public async Task<bool> PurchaseTicketsAsync(int eventId, int quantity)
    {
        var evt = await _context.Events.FindAsync(eventId);
        
        if (evt == null || evt.SeatsAvailable < quantity)
            return false;  // Not enough seats available or the event does not exist

        evt.SeatsAvailable -= quantity;
        
        await _context.SaveChangesAsync();

        return true;
    }
}